#include <bits/stdc++.h>
using namespace std;

const int N=510;

struct Node{
    int x,y,d;
}st,en;

int n,m,dis[N][N][3];
char g[N][N];
queue<Node> q;

void add(int x,int y,int d,int len){
    //printf("Add (%d, %d, %d)\n",x,y,d);
    if(d==0 && !(x>0 && x<=n && y>0 && y<=m && g[x][y]!='#' && g[x][y]!='E' && dis[x][y][d]==0))
        return;
    if(d==1 && !(x>0 && x<=n && y>0 && y<m && g[x][y]!='#' && g[x][y+1]!='#' && dis[x][y][d]==0))
        return;
    if(d==2 && !(x>0 && x<n && y>0 && y<=m && g[x][y]!='#' && g[x+1][y]!='#' && dis[x][y][d]==0))
        return;
    dis[x][y][d]=len,q.push({x,y,d});
}

int main(){
    while(cin>>n>>m,n){
        st={0,0,0};
        for(int i=1;i<=n;i++){
            scanf("%s",g[i]+1);
            for(int j=1;j<=m;j++){
                if(g[i][j]=='X'){
                    if(!st.x)
                        st.x=i,st.y=j,st.d=0;
                    else if(st.y==j-1)
                        st.d=1; // 横躺
                    else
                        st.d=2; // 纵躺
                }
                if(g[i][j]=='O')
                    en={i,j,0}; 
            }
        }
        memset(dis,0,sizeof(dis));
        q.push(st);
        dis[st.x][st.y][st.d]=1;
        while(q.size()){
            int x=q.front().x,y=q.front().y,d=q.front().d,len=dis[x][y][d]+1;
            //printf("%d %d %d\n",x,y,d,len-2);
            q.pop();
            if(d==0){
                add(x-2,y,2,len);
                add(x+1,y,2,len);
                add(x,y-2,1,len);
                add(x,y+1,1,len);
            }else if(d==1){
                add(x-1,y,1,len);
                add(x+1,y,1,len);
                add(x,y-1,0,len);
                add(x,y+2,0,len);
            }else{
                add(x,y-1,2,len);
                add(x,y+1,2,len);
                add(x-1,y,0,len);
                add(x+2,y,0,len);
            }
        }
        if(!dis[en.x][en.y][en.d])
            puts("Impossible");
        else
            printf("%d\n",dis[en.x][en.y][en.d]-1);
    }
    return 0;
}
